    # Try Odoo JSON-RPC style first
    if "/ipai/copilot" in url or "/web" in url:
        payload = {
            "jsonrpc": "2.0",
            "method": "call",
            "params": {"message": prompt},
        }
    else:
        # Fallback: simple JSON POST (marketing Pulser style)
        payload = {
            "message": prompt,
            "sessionId": f"eval-{int(time.time())}",
            "context": {"surface": "eval_runner"},
        }

    start = time.monotonic()
    try:
        resp = requests.post(url, json=payload, timeout=timeout)
        latency_ms = (time.monotonic() - start) * 1000
        resp.raise_for_status()
        data = resp.json()

        # Extract reply from various response shapes
        reply = (
            data.get("result", {}).get("content")
            or data.get("reply")
            or data.get("result", {}).get("reply")
            or str(data)
        )

        return {
            "status": "ok",
            "reply": reply,
            "latency_ms": round(latency_ms),
            "raw": data,
        }
    except requests.Timeout:
        return {"status": "timeout", "reply": "", "latency_ms": round((time.monotonic() - start) * 1000), "raw": {}}
    except requests.RequestException as e:
        return {"status": "error", "reply": "", "latency_ms": 0, "raw": {"error": str(e)}}


def score_case(case: dict[str, Any], response: dict[str, Any]) -> dict[str, Any]:
    """Score a single eval case against its pass criteria."""
    criteria = case.get("pass_criteria", {})
    must_contain = criteria.get("must_contain", [])
    must_not_contain = criteria.get("must_not_contain", [])
    behavior = criteria.get("behavior", "answer")

    reply = response.get("reply", "").lower()
    passed = True
    failures: list[str] = []

    if response["status"] != "ok":
        passed = False
        failures.append(f"endpoint returned {response['status']}")
    else:
        # Check must_contain
        for term in must_contain:
            if term.lower() not in reply:
                passed = False
                failures.append(f"missing required term: '{term}'")

        # Check must_not_contain
        for term in must_not_contain:
            if term.lower() in reply:
                passed = False
                failures.append(f"contains prohibited term: '{term}'")

[]) behavior = criteria.get("behavior", "answer") reply = response.get("reply", "").lower() passed = True failures: list[str] = [] if response["status"] != "ok": passed = False failures.append(f"endpoint returned {response['status']}") else: # Check must_contain for term in must_contain: if term.lower() not in reply: passed = False failures.append(f"missing required term: '{term}'") # Check must_not_contain for term in must_not_contain: if term.lower() in reply: passed = False failures.append(f"contains prohibited term: '{term}'")

        # Check behavior
        if behavior == "refuse" and not any(
            w in reply for w in ["cannot", "can't", "not able", "outside", "beyond", "decline", "sorry"]
        ):
            passed = False
            failures.append("expected refusal but got an answer")

        if behavior == "answer" and len(reply.strip()) < 10:
            passed = False
            failures.append("expected an answer but response is too short")

    return {
        "id": case["id"],
        "category": case.get("category", "unknown"),
        "subcategory": case.get("subcategory", "unknown"),
        "prompt": case["prompt"],
        "pass": passed,
        "failures": failures,
        "response_excerpt": response.get("reply", "")[:200],
        "latency_ms": response.get("latency_ms", 0),
        "status": response.get("status", "unknown"),
    }


def compute_aggregates(scored: list[dict[str, Any]]) -> dict[str, Any]:
    """Compute aggregate scores by category."""
    total = len(scored)
    passed = sum(1 for s in scored if s["pass"])
    failed = sum(1 for s in scored if not s["pass"])

    by_category: dict[str, dict[str, int]] = {}
    for s in scored:
        cat = s["category"]
        if cat not in by_category:
            by_category[cat] = {"total": 0, "passed": 0, "failed": 0}
        by_category[cat]["total"] += 1
        if s["pass"]:
            by_category[cat]["passed"] += 1
        else:
            by_category[cat]["failed"] += 1

    category_rates = {
        cat: round(v["passed"] / v["total"], 4) if v["total"] > 0 else 0
        for cat, v in by_category.items()
    }

    latencies = [s["latency_ms"] for s in scored if s["latency_ms"] > 0]
    latencies.sort()

    return {
        "total_cases": total,
        "passed": passed,
        "failed": failed,
        "pass_rate": round(passed / total, 4) if total > 0 else 0,
        "category_pass_rates": category_rates,
        "category_counts": {cat: v["total"] for cat, v in by_category.items()},
        "latency_p50_ms": latencies[len(latencies) // 2] if latencies else 0,
        "latency_p95_ms": latencies[int(len(latencies) * 0.95)] if latencies else 0,
        "latency_max_ms": max(latencies) if latencies else 0,
        "error_count": sum(1 for s in scored if s["status"] != "ok"),
    }


